impl<S: Signature> CompiledSignature<S> {
    pub fn render_messages_with_ctx<C: serde::Serialize>(
        &self,
        input: &S::Input,
        ctx: C,
    ) -> Result<RenderedMessages, RenderError> {
        // 1. Convert input to BamlValue
        let input_value = input.to_baml_value();

        // 2. Create RenderSession with ctx
        let session = Arc::new(RenderSession::new(self.world.settings.clone())
            .with_ctx(ctx));

        // 3. Build PromptValue for each input field
        let mut inputs_map = minijinja::value::ValueMap::new();

        for field_spec in S::Input::fields() {
            // Get child value from input_value
            let field_value = extract_field(&input_value, field_spec.rust_name)?;
            let field_ty = (field_spec.type_ir)();
            let path = PromptPath::new().push_field(field_spec.rust_name);

            let pv = PromptValue::new(
                field_value,
                field_ty,
                self.world.clone(),
                session.clone(),
                path,
            );

            // Apply field override if present
            let pv = if let Some(override_) = build_field_override(field_spec) {
                pv.with_override(override_)
            } else {
                pv
            };

            inputs_map.insert(
                minijinja::Value::from(field_spec.rust_name),
                pv.as_jinja_value(),
            );
        }

        // 4. Build Jinja context
        let jinja_ctx = minijinja::context\! {
            sig => minijinja::Value::from_serialize(&self.sig_meta),
            inputs => minijinja::Value::from_object(inputs_map),
            ctx => session.ctx.clone(),
        };

        // 5. Render system template
        let system_tmpl = self.world.jinja.get_template(&self.system_template)?;
        let system = system_tmpl.render(&jinja_ctx)?;

        // 6. Render user template
        let user_tmpl = self.world.jinja.get_template(&self.user_template)?;
        let user = user_tmpl.render(&jinja_ctx)?;

        Ok(RenderedMessages { system, user })
    }
}

fn extract_field(value: &BamlValue, field_name: &str) -> Result<BamlValue, RenderError> {
    match value {
        BamlValue::Class(_, fields) => {
            fields.get(field_name).cloned().ok_or_else(|| RenderError {
                message: format\!('missing input field: {}', field_name),
                // ...
            })
        }
        _ => Err(RenderError {
            message: 'input is not a class'.to_string(),
            // ...
        })
    }
}
